import{_ as t,o as n,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"50. Conference Seminar Leave","description":"","frontmatter":{"title":"50. Conference Seminar Leave","eba":"Doctors in Training 2022-2026","topics":["leave","study-leave","preliminary"]},"headers":[],"relativePath":"ebas/doctors-in-training/education-pd/50-conference-seminar-leave.md","filePath":"ebas/doctors-in-training/education-pd/50-conference-seminar-leave.md"}'),a={name:"ebas/doctors-in-training/education-pd/50-conference-seminar-leave.md"};function i(s,e,c,p,h,l){return n(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_50-conference-seminar-leave" tabindex="-1">50. Conference Seminar Leave <a class="header-anchor" href="#_50-conference-seminar-leave" aria-label="Permalink to &quot;50. Conference Seminar Leave&quot;">​</a></h1><p><strong>50.1</strong> Entitlement</p><p><strong>(a)</strong> A Doctor’s entitlement to paid Conference/Seminar leave is up to a total three weeks per year of service as follows:</p><p><strong>(i)</strong> a minimum of one week (minimum entitlement); and</p><p><strong>(ii)</strong> up to a further two weeks at the discretion of the Health Service (additional entitlement).</p><p><strong>(b)</strong> The minimum entitlement of one week each year as described at subclause 50.1(a)(i) may be accrued over two years to suit particular study requirements.</p><p><strong>(c)</strong> Paid Conference/Seminar leave, including the minimum entitlement, may be taken in periods of less than a week.</p><p><strong>50.2</strong> Definitions</p><p>In this clause, Conference/Seminar means a conference, workshop or seminar that is directly relevant to the Doctor’s role and/or education.</p><p><strong>50.3</strong> Application for Conference/Seminar leave</p><p><strong>(a)</strong> A Doctor must apply for Conference/Seminar leave by</p><p><strong>(i)</strong> 31 March of the year in which the leave will be taken; or</p><p><strong>(ii)</strong> such offer date published by the Health Service; or</p><p><strong>(iii)</strong> otherwise with not less than three months’ notice.</p><p><strong>(b)</strong> An application for Conference/Seminar leave shall include the nominated dates for taking paid Conference/Seminar leave.</p><p><strong>(c)</strong> A Health Service must respond to an application for Conference/Seminar leave:</p><p><strong>(i)</strong> within 14 days of the date specified at either clause 50.3(a)(i) or (ii); or</p><p><strong>(ii)</strong> for all other applications, within 14 days or other date advised to the Doctor within 14 days, to ensure all applications can be considered rather than a &#39;first in, best dressed&#39; approach.</p><p><strong>50.4</strong> Granting of Conference Leave – Minimum Entitlement</p><p><strong>(a)</strong> A Health Service may only refuse the entitlement where:</p><p><strong>(i)</strong> the refusal is based on circumstances outside the control of the Health Service; and</p><p><strong>(ii)</strong> the reasons for the refusal are provided to the Doctor in writing within 14 days of the application for leave being received by the Health Service.</p><p><strong>(b)</strong> A Doctor who has had their application for the minimum one week’s paid Conference/Seminar leave refused may utilise the Dispute Resolution Procedure set out in <a href="/eba/ebas/doctors-in-training/consultation-disputes/12-dispute-resolution-procedure.html">clause 12</a> of this Agreement.</p><p><strong>50.5</strong> Granting of Conference Leave – Additional Entitlement</p><p><strong>(a)</strong> The timing of the conference leave granted under this clause 50 is subject to Health Service operational requirements. Practical restrictions on the ability to release a Doctor at any particular time will exist on some occasions.</p><p><strong>(b)</strong> Where for operational reasons, the Health Service cannot accommodate the nominated dates of Conference/Seminar leave nominated by the Doctor, the Health Service must advise the Doctor, in writing, the reasons for not accommodating the nominated dates.</p><p><strong>(c)</strong> Where a Doctor who has had their application for their nominated dates refused, the Doctor may utilise the Dispute Resolution Procedure set out in <a href="/eba/ebas/doctors-in-training/consultation-disputes/12-dispute-resolution-procedure.html">clause 12</a> of this Agreement.</p><p><strong>50.6</strong> Payment Calculation</p><p><strong>(a)</strong> Payment for Conference/Seminar leave pursuant to this clause 50 must be made consistent with the roster or projected roster, excluding overtime and penalties.</p><p><strong>(b)</strong> In this clause 50, projected roster means the roster the Employee would have worked had they not taken the leave. This can be determined by:</p><p><strong>(i)</strong> the Doctor’s pattern of work over the preceding three (3) months or the Doctor’s period of employment where the Doctor has been employed for less than 3 months; or</p><p><strong>(ii)</strong> in the absence of a pattern of work, whether the Doctor worked at least 50% of the relevant day over the preceding three (3) months of the Doctor’s period of employment where the Doctors has been employed for less than 3 months.</p><p>Plain language terms: conference leave.</p>',33)])])}const f=t(a,[["render",i]]);export{m as __pageData,f as default};
